import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import Toast from '../common/Toast';
import Loader from '../common/Loader';

interface Sector {
  id: number;
  name: string;
  description: string;
  isActive: boolean;
}

type QuestionType = 'radio' | 'checkbox' | 'text' | 'textarea' | 'rating';

interface Question {
  id: number;
  sectorId: number;
  type: QuestionType;
  text: string;
  options: string[] | null;
  required: boolean;
  order: number;
  isActive: boolean;
  createdAt: string;
  updatedAt: string;
}

interface QuestionFormData {
  type: QuestionType;
  text: string;
  options: string[];
  required: boolean;
  order: number;
}

const QuestionEditor: React.FC = () => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [sectors, setSectors] = useState<Sector[]>([]);
  const [selectedSector, setSelectedSector] = useState<number | null>(null);
  const [loading, setLoading] = useState(true);
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
  const [showToast, setShowToast] = useState(false);
  const [toastMessage, setToastMessage] = useState('');
  const [toastType, setToastType] = useState<'success' | 'error'>('success');
  const [showSectorModal, setShowSectorModal] = useState(false);
  const [showQuestionModal, setShowQuestionModal] = useState(false);
  const [newSector, setNewSector] = useState({ name: '', description: '' });
  const [questionForm, setQuestionForm] = useState<QuestionFormData>({
    type: 'radio',
    text: '',
    options: [],
    required: false,
    order: 0,
  });
  const [optionsInput, setOptionsInput] = useState('');

  useEffect(() => {
    fetchSectors();
  }, []);

  useEffect(() => {
    if (selectedSector) {
      fetchQuestions();
    }
  }, [selectedSector]);

  const fetchSectors = async () => {
    try {
      const response = await api.get('/api/sectors/admin');
      setSectors(response.data);
      if (response.data.length > 0) {
        setSelectedSector(response.data[0].id);
      }
    } catch (err) {
      showMessage('Failed to load sectors', 'error');
    } finally {
      setLoading(false);
    }
  };

  const fetchQuestions = async () => {
    if (!selectedSector) return;
    try {
      const response = await api.get(`/api/sectors/${selectedSector}/questions`);
      setQuestions(response.data);
    } catch (err) {
      showMessage('Failed to load questions', 'error');
    }
  };

  const showMessage = (message: string, type: 'success' | 'error') => {
    setToastMessage(message);
    setToastType(type);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleCreateSector = async () => {
    if (!newSector.name.trim()) {
      showMessage('Sector name is required', 'error');
      return;
    }
    try {
      const response = await api.post('/api/sectors', newSector);
      setSectors([...sectors, response.data]);
      setSelectedSector(response.data.id);
      setShowSectorModal(false);
      setNewSector({ name: '', description: '' });
      showMessage('Sector created successfully!', 'success');
    } catch (err) {
      showMessage('Failed to create sector', 'error');
    }
  };

  const handleEditQuestion = (question: Question) => {
    setEditingQuestion(question);
    setQuestionForm({
      type: question.type,
      text: question.text,
      options: question.options || [],
      required: question.required,
      order: question.order,
    });
    if (question.options) {
      setOptionsInput(question.options.join('\n'));
    } else {
      setOptionsInput('');
    }
    setShowQuestionModal(true);
  };

  const handleSaveQuestion = async () => {
    if (!questionForm.text) {
      showMessage('Question text is required', 'error');
      return;
    }

    if ((questionForm.type === 'radio' || questionForm.type === 'checkbox') && !optionsInput.trim()) {
      showMessage('Options are required for radio/checkbox questions', 'error');
      return;
    }

    const data = {
      type: questionForm.type,
      text: questionForm.text,
      options: optionsInput ? optionsInput.split('\n').filter(o => o.trim()) : null,
      required: questionForm.required,
      order: questionForm.order,
    };

    try {
      if (editingQuestion) {
        await api.put(`/api/questions/${editingQuestion.id}`, data);
        showMessage('Question updated successfully!', 'success');
      } else {
        await api.post(`/api/sectors/${selectedSector}/questions`, data);
        showMessage('Question created successfully!', 'success');
      }
      setShowQuestionModal(false);
      setEditingQuestion(null);
      setQuestionForm({ type: 'radio', text: '', options: [], required: false, order: 0 });
      setOptionsInput('');
      fetchQuestions();
    } catch (err) {
      showMessage('Failed to save question', 'error');
    }
  };

  const handleDeleteQuestion = async (id: number) => {
    if (!window.confirm('Are you sure you want to delete this question?')) return;
    try {
      await api.delete(`/api/questions/${id}`);
      showMessage('Question deleted successfully!', 'success');
      fetchQuestions();
    } catch (err) {
      showMessage('Failed to delete question', 'error');
    }
  };

  const handleReorder = async (id: number, direction: 'up' | 'down') => {
    const currentIndex = questions.findIndex(q => q.id === id);
    if (direction === 'up' && currentIndex === 0) return;
    if (direction === 'down' && currentIndex === questions.length - 1) return;

    const newOrder = [...questions];
    const swapIndex = direction === 'up' ? currentIndex - 1 : currentIndex + 1;
    [newOrder[currentIndex], newOrder[swapIndex]] = [newOrder[swapIndex], newOrder[currentIndex]];

    try {
      await api.put('/api/questions/reorder', {
        questions: newOrder.map((q, idx) => ({ id: q.id, order: idx }))
      });
      fetchQuestions();
      showMessage('Order updated!', 'success');
    } catch (err) {
      showMessage('Failed to reorder questions', 'error');
    }
  };

  const toggleQuestionActive = async (question: Question) => {
    try {
      await api.put(`/api/questions/${question.id}`, { isActive: !question.isActive });
      fetchQuestions();
      showMessage(`Question ${question.isActive ? 'disabled' : 'enabled'}`, 'success');
    } catch (err) {
      showMessage('Failed to update question status', 'error');
    }
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value as QuestionType;
    setQuestionForm(prev => ({ ...prev, type: newType }));
  };

  const renderQuestionPreview = (question: Question) => {
    switch (question.type) {
      case 'rating':
        return (
          <div style={styles.previewRating}>
            {[1, 2, 3, 4, 5].map(num => (
              <span key={num} style={styles.previewRatingStar}>
                {num === 5 ? '★' : num === 1 ? '☆' : num}
              </span>
            ))}
          </div>
        );
      case 'radio':
        return (
          <div style={styles.previewOptions}>
            {question.options?.slice(0, 3).map((opt, i) => (
              <div key={i} style={styles.previewOption}>
                <span style={styles.previewRadio}></span> {opt}
              </div>
            ))}
            {question.options && question.options.length > 3 && (
              <div style={styles.previewMore}>+{question.options.length - 3} more</div>
            )}
          </div>
        );
      case 'checkbox':
        return (
          <div style={styles.previewOptions}>
            {question.options?.slice(0, 3).map((opt, i) => (
              <div key={i} style={styles.previewOption}>
                <span style={styles.previewCheckbox}></span> {opt}
              </div>
            ))}
            {question.options && question.options.length > 3 && (
              <div style={styles.previewMore}>+{question.options.length - 3} more</div>
            )}
          </div>
        );
      case 'text':
        return <div style={styles.previewInput}>[Short text input]</div>;
      case 'textarea':
        return <div style={styles.previewTextarea}>[Multi-line text input]</div>;
      default:
        return null;
    }
  };

  if (loading) return <Loader fullScreen />;

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>📝 Question Editor</h2>
      <p style={styles.subtitle}>Create, edit, and manage questions for different sectors</p>

      {showToast && (
        <Toast message={toastMessage} type={toastType} onClose={() => setShowToast(false)} />
      )}

      {/* Sector Selector */}
      <div style={styles.sectorSelector}>
        <div style={styles.sectorSelectorLeft}>
          <label style={styles.label}>Select Sector:</label>
          <select
            value={selectedSector || ''}
            onChange={(e) => setSelectedSector(parseInt(e.target.value))}
            style={styles.select}
          >
            {sectors.map(sector => (
              <option key={sector.id} value={sector.id}>{sector.name}</option>
            ))}
          </select>
        </div>
        <div style={styles.sectorSelectorRight}>
          <button onClick={() => setShowSectorModal(true)} style={styles.addSectorBtn}>
            + Add Sector
          </button>
          <button onClick={() => {
            setEditingQuestion(null);
            setQuestionForm({ type: 'radio', text: '', options: [], required: false, order: questions.length });
            setOptionsInput('');
            setShowQuestionModal(true);
          }} style={styles.addQuestionBtn}>
            + Add Question
          </button>
        </div>
      </div>

      {/* Questions List */}
      <div style={styles.questionsList}>
        <h3>Questions for {sectors.find(s => s.id === selectedSector)?.name}</h3>
        {questions.length === 0 ? (
          <div style={styles.emptyState}>
            <p>No questions yet. Click "Add Question" to create your first question!</p>
          </div>
        ) : (
          questions.map((question, index) => (
            <div key={question.id} style={styles.questionCard}>
              <div style={styles.questionHeader}>
                <div style={styles.questionNumber}>Q{index + 1}</div>
                <div style={styles.questionTypeBadge}>{question.type.toUpperCase()}</div>
                {question.required && <div style={styles.requiredBadge}>Required</div>}
                {!question.isActive && <div style={styles.inactiveBadge}>Inactive</div>}
                <div style={styles.reorderButtons}>
                  <button
                    onClick={() => handleReorder(question.id, 'up')}
                    disabled={index === 0}
                    style={styles.reorderBtn}
                    title="Move Up"
                  >
                    ↑
                  </button>
                  <button
                    onClick={() => handleReorder(question.id, 'down')}
                    disabled={index === questions.length - 1}
                    style={styles.reorderBtn}
                    title="Move Down"
                  >
                    ↓
                  </button>
                </div>
              </div>
              
              <div style={styles.questionText}>{question.text}</div>
              
              <div style={styles.questionPreview}>
                <div style={styles.previewLabel}>Preview:</div>
                {renderQuestionPreview(question)}
              </div>
              
              {question.options && question.options.length > 0 && (
                <div style={styles.optionsList}>
                  <span style={styles.optionsLabel}>Options:</span>
                  {question.options.map((opt, i) => (
                    <span key={i} style={styles.optionTag}>{opt}</span>
                  ))}
                </div>
              )}
              
              <div style={styles.questionActions}>
                <button onClick={() => handleEditQuestion(question)} style={styles.editBtn}>
                  ✏️ Edit
                </button>
                <button onClick={() => toggleQuestionActive(question)} style={question.isActive ? styles.disableBtn : styles.enableBtn}>
                  {question.isActive ? '🔴 Disable' : '🟢 Enable'}
                </button>
                <button onClick={() => handleDeleteQuestion(question.id)} style={styles.deleteBtn}>
                  🗑️ Delete
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Add/Edit Question Modal */}
      {showQuestionModal && (
        <div style={styles.modalOverlay}>
          <div style={styles.modal}>
            <h3>{editingQuestion ? 'Edit Question' : 'Add New Question'}</h3>
            
            <div style={styles.formGroup}>
              <label style={styles.label}>Question Type</label>
              <select
                value={questionForm.type}
                onChange={handleTypeChange}
                style={styles.select}
              >
                <option value="rating">⭐ Rating (1-5)</option>
                <option value="radio">🔘 Radio (Single Choice)</option>
                <option value="checkbox">☑️ Checkbox (Multiple Choice)</option>
                <option value="text">📝 Short Text</option>
                <option value="textarea">📄 Long Text</option>
              </select>
            </div>

            <div style={styles.formGroup}>
              <label style={styles.label}>Question Text</label>
              <textarea
                value={questionForm.text}
                onChange={(e) => setQuestionForm({ ...questionForm, text: e.target.value })}
                style={styles.textarea}
                rows={3}
                placeholder="Enter your question here..."
              />
            </div>

            {(questionForm.type === 'radio' || questionForm.type === 'checkbox') && (
              <div style={styles.formGroup}>
                <label style={styles.label}>Options (one per line)</label>
                <textarea
                  value={optionsInput}
                  onChange={(e) => setOptionsInput(e.target.value)}
                  style={styles.textarea}
                  rows={5}
                  placeholder="Option 1&#10;Option 2&#10;Option 3&#10;Option 4&#10;Option 5"
                />
                <small style={styles.helperText}>Each line becomes a selectable option</small>
              </div>
            )}

            <div style={styles.formGroup}>
              <label style={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={questionForm.required}
                  onChange={(e) => setQuestionForm({ ...questionForm, required: e.target.checked })}
                />
                Required Question
              </label>
            </div>

            <div style={styles.modalButtons}>
              <button onClick={handleSaveQuestion} style={styles.saveBtn}>
                {editingQuestion ? 'Update Question' : 'Create Question'}
              </button>
              <button onClick={() => {
                setShowQuestionModal(false);
                setEditingQuestion(null);
              }} style={styles.cancelBtn}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add Sector Modal */}
      {showSectorModal && (
        <div style={styles.modalOverlay}>
          <div style={styles.modal}>
            <h3>Create New Sector</h3>
            <div style={styles.formGroup}>
              <label style={styles.label}>Sector Name</label>
              <input
                type="text"
                value={newSector.name}
                onChange={(e) => setNewSector({ ...newSector, name: e.target.value })}
                style={styles.input}
                placeholder="e.g., Education, Healthcare, Government"
              />
            </div>
            <div style={styles.formGroup}>
              <label style={styles.label}>Description (Optional)</label>
              <textarea
                value={newSector.description}
                onChange={(e) => setNewSector({ ...newSector, description: e.target.value })}
                style={styles.textarea}
                rows={3}
                placeholder="Describe this sector..."
              />
            </div>
            <div style={styles.modalButtons}>
              <button onClick={handleCreateSector} style={styles.saveBtn}>Create</button>
              <button onClick={() => setShowSectorModal(false)} style={styles.cancelBtn}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

